class Solution {
    public int maxScore(int[] nums) {
        Arrays.sort(nums);
        int n = nums.length / 2;
        int res = 0;
        for (int i = n - 1; i >= 0; i--) {
            res += (n - i) * gcd(nums[i], nums[2 * n - 1 - i]);
        }
        return res;
    }

    private int gcd(int a, int b) {
        if (b == 0) return a;
        return gcd(b, a % b);
    }
}
